css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: 'Georgia', 'Times New Roman', serif; background: #fff5f7; color: #4a2030; }
.page { max-width: 800px; margin: 0 auto; }
.hero { text-align: center; padding: 80px 40px 60px; background: linear-gradient(180deg, #fff0f5, #fff5f7); border-bottom: 1px solid #ffd6e0; }
.hero-decoration { font-size: 48px; color: #ec4899; margin-bottom: 20px; font-family: serif; }
.names { font-size: 56px; font-weight: 700; color: #4a2030; margin-bottom: 8px; font-style: italic; } .names span { color: #ec4899; }
.subtitle { font-size: 18px; color: #be185d; letter-spacing: 4px; margin-bottom: 20px; font-family: sans-serif; }
.date-badge { display: inline-block; background: #ec4899; color: white; padding: 10px 24px; border-radius: 30px; font-size: 15px; font-weight: 600; margin-bottom: 24px; font-family: sans-serif; }
.invite-text { font-size: 17px; line-height: 1.9; color: #6b3045; max-width: 520px; margin: 0 auto 36px; }
.countdown { display: flex; justify-content: center; align-items: center; gap: 16px; }
.cd-item { text-align: center; } .cd-item strong { display: block; font-size: 42px; font-weight: 900; color: #ec4899; font-family: sans-serif; } .cd-item span { font-size: 12px; color: #9ca3af; letter-spacing: 2px; font-family: sans-serif; }
.cd-sep { font-size: 36px; color: #fda4af; font-weight: 300; margin-bottom: 16px; }
.details { display: grid; grid-template-columns: repeat(3, 1fr); gap: 0; border-bottom: 1px solid #ffd6e0; }
.detail-card { padding: 48px 32px; text-align: center; border-right: 1px solid #ffd6e0; } .detail-card:last-child { border-right: none; }
.dc-icon { font-size: 40px; margin-bottom: 16px; }
.detail-card h3 { font-size: 20px; font-weight: 700; color: #4a2030; margin-bottom: 12px; }
.detail-card p { font-size: 14px; color: #6b3045; line-height: 1.8; font-family: sans-serif; }
.venue { color: #ec4899; font-weight: 600; margin-top: 4px; }
.rsvp { padding: 60px 40px; text-align: center; }
.rsvp h2 { font-size: 36px; font-weight: 700; margin-bottom: 10px; } .rsvp > p { color: #9ca3af; font-family: sans-serif; font-size: 14px; margin-bottom: 32px; }
.rsvp-form { max-width: 440px; margin: 0 auto; display: flex; flex-direction: column; gap: 14px; }
.rsvp-form input { height: 52px; border-radius: 14px; border: 1px solid #ffd6e0; background: white; padding: 0 18px; font-size: 15px; color: #4a2030; outline: none; font-family: inherit; } input:focus { border-color: #ec4899; }
.rsvp-choices { display: flex; gap: 12px; }
.rsvp-btn { flex: 1; height: 48px; border-radius: 14px; border: 1px solid #ffd6e0; background: transparent; font-size: 14px; font-weight: 700; cursor: pointer; font-family: sans-serif; transition: all 0.2s; color: #9ca3af; } .rsvp-btn.yes.active { background: #22c55e; border-color: #22c55e; color: white; } .rsvp-btn.no.active { background: #ef4444; border-color: #ef4444; color: white; }
.submit-btn { height: 52px; border-radius: 14px; border: none; background: linear-gradient(135deg, #ec4899, #be185d); color: white; font-size: 16px; font-weight: 700; cursor: pointer; font-family: sans-serif; }
.rsvp-msg { margin-top: 16px; font-size: 15px; min-height: 22px; font-family: sans-serif; }
.footer { padding: 40px; text-align: center; background: #4a2030; color: white; }
.footer-names { font-size: 28px; font-style: italic; margin-bottom: 8px; }
.footer p { color: rgba(255,255,255,0.6); font-family: sans-serif; font-size: 14px; margin-bottom: 12px; }
.hearts { font-size: 24px; }

js:
let rsvpChoice = 'yes';
function setRsvp(choice, btn) { rsvpChoice = choice; document.querySelectorAll('.rsvp-btn').forEach(b => b.classList.remove('active')); btn.classList.add('active'); }
function submitRsvp() {
  const name = document.getElementById('rsvp-name').value.trim();
  const count = document.getElementById('rsvp-count').value;
  const msg = document.getElementById('rsvp-msg');
  if (!name) { msg.style.color = '#ef4444'; msg.textContent = '⚠️ Lütfen adınızı girin.'; return; }
  if (rsvpChoice === 'yes') { msg.style.color = '#22c55e'; msg.textContent = '✓ Teşekkürler ' + name + '! ' + (count||1) + ' kişi için rezervasyon yapıldı. Sizi görmekten mutluluk duyacağız! 💕'; }
  else { msg.style.color = '#6b7280'; msg.textContent = 'Anlıyoruz, ' + name + '. Katılamadığınız için üzgünüz. Dilekleriniz için teşekkürler! 🌹'; }
}
function updateCountdown() {
  const target = new Date('2025-02-14T15:00:00');
  const now = new Date();
  const diff = target - now;
  if (diff <= 0) { document.getElementById('countdown').innerHTML = '<strong style="color:#ec4899;font-size:24px">Bugün Evleniyoruz! 💕</strong>'; return; }
  const d = Math.floor(diff / 86400000);
  const h = Math.floor((diff % 86400000) / 3600000);
  const m = Math.floor((diff % 3600000) / 60000);
  const s = Math.floor((diff % 60000) / 1000);
  document.getElementById('cd-d').textContent = String(d).padStart(2,'0');
  document.getElementById('cd-h').textContent = String(h).padStart(2,'0');
  document.getElementById('cd-m').textContent = String(m).padStart(2,'0');
  document.getElementById('cd-s').textContent = String(s).padStart(2,'0');
}
setInterval(updateCountdown, 1000);
updateCountdown();
